/**
 * CurrentOrg Decorator
 *
 * Parameter decorator for extracting the current organization (tenant) from request.
 * Works with routing-controllers and the tenant middleware.
 *
 * @module shared/decorators/current-org
 */

import { createParamDecorator } from 'routing-controllers';
import { Request } from 'express';
import {
  TenantOrganization,
  TenantRequest,
  OptionalTenantRequest,
} from '@/core/middleware/tenant.middleware';
import { AppException } from '@/core/exceptions/app.exception';

/**
 * Options for the CurrentOrg decorator
 */
export interface CurrentOrgOptions {
  /**
   * Whether the organization is required. If true, throws when no org context.
   * @default true
   */
  required?: boolean;
}

/**
 * Parameter decorator that extracts the current organization from the request.
 *
 * The decorator retrieves the `organization` object attached by the tenant middleware
 * and provides it as a parameter to the controller method.
 *
 * IMPORTANT: This decorator enforces multi-tenant data isolation by ensuring
 * every controller method explicitly receives the organization context.
 *
 * @param options - Decorator options
 * @returns Parameter decorator
 *
 * @throws {AppException} BAD_REQUEST - When organization context is missing (if required: true)
 *
 * @example
 * ```typescript
 * import { CurrentOrg } from '@/shared/decorators';
 * import { TenantOrganization } from '@/core/middleware/tenant.middleware';
 *
 * @JsonController('/api/v1/menus')
 * @injectable()
 * export class MenuController extends BaseController {
 *
 *   @Get('/')
 *   @Authorized(['menu.view'])
 *   async list(
 *     @CurrentOrg() org: TenantOrganization,
 *     @QueryParams() query: ListMenusQuery,
 *   ): Promise<ApiResponse<Menu[]>> {
 *     // CRITICAL: Always use org.id in queries for tenant isolation
 *     const menus = await this.menuService.findAll(org.id, query);
 *     return this.success(menus);
 *   }
 *
 *   @Post('/')
 *   @Authorized(['menu.create'])
 *   async create(
 *     @CurrentOrg() org: TenantOrganization,
 *     @Body() data: CreateMenuDto,
 *   ): Promise<ApiResponse<Menu>> {
 *     const menu = await this.menuService.create(org.id, data);
 *     return this.created(menu);
 *   }
 * }
 * ```
 *
 * @example Optional organization context
 * ```typescript
 * // For public endpoints that can work with or without tenant context
 * @Get('/public')
 * async getPublicData(
 *   @CurrentOrg({ required: false }) org?: TenantOrganization,
 * ): Promise<ApiResponse<PublicData>> {
 *   if (org) {
 *     // Show tenant-specific data
 *   }
 *   return this.success(data);
 * }
 * ```
 */
export function CurrentOrg(options: CurrentOrgOptions = {}): ParameterDecorator {
  const { required = true } = options;

  return createParamDecorator({
    required,
    value: (action): TenantOrganization | undefined => {
      const req = action.request as TenantRequest;

      if (!req.organization) {
        if (required) {
          throw AppException.badRequest('Organization context required');
        }
        return undefined;
      }

      return req.organization;
    },
  });
}

/**
 * Parameter decorator that extracts only the organization ID from the request.
 *
 * Use this when you only need the organization ID and not the full entity.
 * This is a convenience decorator that returns just the string ID.
 *
 * @param options - Decorator options
 * @returns Parameter decorator
 *
 * @throws {AppException} BAD_REQUEST - When organization context is missing (if required: true)
 *
 * @example
 * ```typescript
 * import { CurrentOrgId } from '@/shared/decorators';
 *
 * @Get('/')
 * async list(
 *   @CurrentOrgId() orgId: string,
 *   @QueryParams() query: ListQuery,
 * ): Promise<ApiResponse<Menu[]>> {
 *   const menus = await this.menuService.findAll(orgId, query);
 *   return this.success(menus);
 * }
 * ```
 */
export function CurrentOrgId(options: CurrentOrgOptions = {}): ParameterDecorator {
  const { required = true } = options;

  return createParamDecorator({
    required,
    value: (action): string | undefined => {
      const req = action.request as TenantRequest;

      if (!req.organization) {
        if (required) {
          throw AppException.badRequest('Organization context required');
        }
        return undefined;
      }

      return req.organization.id;
    },
  });
}

/**
 * Gets the current organization from request.
 * Utility function for use in middleware or services.
 *
 * @param req - Express request object
 * @returns Organization context
 * @throws {AppException} BAD_REQUEST - When organization context is missing
 *
 * @example
 * ```typescript
 * import { getCurrentOrg } from '@/shared/decorators';
 *
 * const org = getCurrentOrg(req);
 * const menus = await menuService.findAll(org.id);
 * ```
 */
export function getCurrentOrg(req: Request): TenantOrganization {
  const tenantReq = req as TenantRequest;

  if (!tenantReq.organization) {
    throw AppException.badRequest('Organization context required');
  }

  return tenantReq.organization;
}

/**
 * Gets the current organization from request, or undefined if not set.
 * Utility function for use in middleware or services where org is optional.
 *
 * @param req - Express request object
 * @returns Organization context or undefined
 *
 * @example
 * ```typescript
 * import { getCurrentOrgOptional } from '@/shared/decorators';
 *
 * const org = getCurrentOrgOptional(req);
 * if (org) {
 *   // Show organization-specific content
 * }
 * ```
 */
export function getCurrentOrgOptional(req: Request): TenantOrganization | undefined {
  return (req as OptionalTenantRequest).organization;
}

/**
 * Gets the current organization ID from request.
 * Utility function for use in middleware or services.
 *
 * @param req - Express request object
 * @returns Organization ID string
 * @throws {AppException} BAD_REQUEST - When organization context is missing
 *
 * @example
 * ```typescript
 * import { getCurrentOrgId } from '@/shared/decorators';
 *
 * const orgId = getCurrentOrgId(req);
 * const menus = await prisma.menu.findMany({
 *   where: { organizationId: orgId, deletedAt: null }
 * });
 * ```
 */
export function getCurrentOrgId(req: Request): string {
  return getCurrentOrg(req).id;
}

/**
 * Checks if the request has organization context.
 *
 * @param req - Express request object
 * @returns True if organization context is set
 *
 * @example
 * ```typescript
 * import { hasOrgContext } from '@/shared/decorators';
 *
 * if (hasOrgContext(req)) {
 *   const org = getCurrentOrg(req);
 * }
 * ```
 */
export function hasOrgContext(req: Request): boolean {
  return (req as OptionalTenantRequest).organization !== undefined;
}

/**
 * Validates that the given organization ID matches the current tenant context.
 * Use this to prevent cross-tenant data access.
 *
 * @param req - Express request object
 * @param organizationId - Organization ID to validate
 * @throws {AppException} TENANT_ACCESS_DENIED - When IDs don't match
 *
 * @example
 * ```typescript
 * import { validateOrgAccess } from '@/shared/decorators';
 *
 * // In a service method
 * validateOrgAccess(req, resource.organizationId);
 * await this.repository.delete(resourceId);
 * ```
 */
export function validateOrgAccess(req: Request, organizationId: string): void {
  const currentOrg = getCurrentOrgOptional(req);

  if (!currentOrg) {
    throw AppException.badRequest('Organization context required');
  }

  if (currentOrg.id !== organizationId) {
    throw AppException.tenantAccessDenied(organizationId);
  }
}
